const md = $input.item.json.content;

// Custom markdown-to-styled HTML parser for video emails
function parseMarkdown(markdown) {
  if (!markdown) return '';

  let html = markdown
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n');

  // Convert must watch video headers & blocks
  // Matches: ### [title](url)
  //          **Channel:** `author` | **Watch Link:** ...
  //          > summary
  html = html.replace(/### \[(.*?)\]\((.*?)\)\n\*\*Channel:\*\* `(.*?)` \| \*\*Watch Link:\*\* \[.*?\]\(.*?\)\n> (.*?)(?=\n\n|\n###|\n##|$)/g, 
    '<div class="must-watch-card">' +
    '  <h3><a href="$2" target="_blank">$1</a></h3>' +
    '  <div class="meta">' +
    '    <span class="badge badge-primary">$3</span>' +
    '    <a class="btn-watch" href="$2" target="_blank">Watch on YouTube ➔</a>' +
    '  </div>' +
    '  <blockquote>$4</blockquote>' +
    '</div>'
  );

  // Convert remaining sections
  // Headers
  html = html.replace(/^# (.*)$/gm, '<h1 class="main-title">$1</h1>')
             .replace(/^## 🔥 Must Watch$/gm, '<h2 class="section-header"><span style="color:#f59e0b">🔥</span> Must Watch Videos</h2>')
             .replace(/^## 🎥 More Video Releases$/gm, '<h2 class="section-header"><span style="color:#3b82f6">🎥</span> More Video Releases</h2>')
             .replace(/^## ⭐ Analyst Insights$/gm, '') // Handled separately to wrap
             .replace(/^## 🔗 Sources & Videos Reference$/gm, '<h2 class="section-header"><span style="color:#64748b">🔗</span> Reference Catalogue</h2>')
             .replace(/^#### (.*)$/gm, '<h4 class="sub-header">$1</h4>');

  // Convert list items: - **[title](url)** - `author` Description...
  html = html.replace(/^- \*\*\[(.*?)\]\((.*?)\)\*\* - `(.*?)`\n\s+\*Description: (.*?)\*$/gm, 
    '<li class="video-list-item">' +
    '  <a class="video-link" href="$2" target="_blank">$1</a>' +
    '  <div class="meta-inline"><span class="badge badge-secondary">$3</span></div>' +
    '  <p class="desc">$4</p>' +
    '</li>'
  );

  // Table parsing
  html = html.replace(/\| (.+?) \|/g, '<td>$1</td>')
             .replace(/<\/td>\n<td>/g, '</td><td>')
             .replace(/^- (.*)$/gm, '<li>$1</li>');

  let lines = html.split('\n');
  let inTable = false;
  for (let i = 0; i < lines.length; i++) {
    if (lines[i].includes('<td>')) {
      if (!inTable) {
        lines[i] = '<table class="ref-table"><tr>' + lines[i] + '</tr>';
        inTable = true;
      } else {
        if (lines[i].includes('---')) {
          lines[i] = ''; 
        } else {
          lines[i] = '<tr>' + lines[i] + '</tr>';
        }
      }
    } else {
      if (inTable) {
        lines[i] = '</table>' + lines[i];
        inTable = false;
      }
    }
  }
  html = lines.join('\n');

  // Convert links & bold in remaining text
  html = html.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
             .replace(/\*(.*?)\*/g, '<em>$1</em>')
             .replace(/`([^`]+)`/g, '<code>$1</code>')
             .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" target="_blank">$1</a>')
             .replace(/((?:<li>.*<\/li>\n?)+)/g, '<ul>$1</ul>')
             .replace(/^> (.*)$/gm, '<blockquote>$1</blockquote>');

  // Split by insights header to wrap in styled container
  if (html.includes('## ⭐ Analyst Insights')) {
    let parts = html.split('## ⭐ Analyst Insights');
    let mainContent = parts[0];
    let insightsAndFooter = parts[1];

    // Split references out of insights
    let subParts = insightsAndFooter.split('<h2 class="section-header"><span style="color:#64748b">🔗</span> Reference Catalogue</h2>');
    let insightsBody = subParts[0];
    let referenceTable = subParts[1] || '';

    html = mainContent + 
           '<div class="insights-container">' +
           '  <div class="insights-header">⭐ Analyst Synthesis & Insights</div>' +
           insightsBody +
           '</div>' +
           '<h2 class="section-header"><span style="color:#64748b">🔗</span> Reference Catalogue</h2>' +
           referenceTable;
  }

  // Clean up double breaks
  html = html.replace(/\n\n/g, '<br>');

  return html;
}

const parsedHtml = parseMarkdown(md);

